    // 3. Register nodes
    graph.addNode(source);
    graph.addNode(observer);
    graph.addNode(transitive_observer);

    // 4. Set up direct observer relationship: source observes observer
    source->addOneObserver(observer);

    // 5. Set up transitive observer relationship: source observes transitive_observer, which observes observer
    source->addOneObserver(transitive_observer);
    transitive_observer->addOneObserver(observer);

